# Inspect gradient statistics after backward()
def report_gradients(model):
    for name, param in model.named_parameters():
        if param.grad is not None:
            g = param.grad
            print(f"{name:30s}  norm={g.norm():.4f}  "
                  f"min={g.min():.4f}  max={g.max():.4f}")
        else:
            print(f"{name:30s}  grad=None (frozen or unused)")

loss.backward()
report_gradients(model)

from torch.utils.checkpoint import checkpoint

class CheckpointedBlock(nn.Module):
    def __init__(self, layer):
        super().__init__()
        self.layer = layer

    def forward(self, x):
        # Recomputes self.layer's forward during backward instead of storing activations
        return checkpoint(self.layer, x)
